        0x04, 0xc7, 0x23, 0xc3, 0x18, 0x96, 0x05, 0x9a, 0x07, 0x12, 0x80, 0xe2, 0xeb, 0x27, 0xb2, 0x75,
        0x09, 0x83, 0x2c, 0x1a, 0x1b, 0x6e, 0x5a, 0xa0, 0x52, 0x3b, 0xd6, 0xb3, 0x29, 0xe3, 0x2f, 0x84,
        0x53, 0xd1, 0x00, 0xed, 0x20, 0xfc, 0xb1, 0x5b, 0x6a, 0xcb, 0xbe, 0x39, 0x4a, 0x4c, 0x58, 0xcf,
        0xd0, 0xef, 0xaa, 0xfb, 0x43, 0x4d, 0x33, 0x85, 0x45, 0xf9, 0x02, 0x7f, 0x50, 0x3c, 0x9f, 0xa8,
        0x51, 0xa3, 0x40, 0x8f, 0x92, 0x9d, 0x38, 0xf5, 0xbc, 0xb6, 0xda, 0x21, 0x10, 0xff, 0xf3, 0xd2,
        0xcd, 0x0c, 0x13, 0xec, 0x5f, 0x97, 0x44, 0x17, 0xc4, 0xa7, 0x7e, 0x3d, 0x64, 0x5d, 0x19, 0x73,
        0x60, 0x81, 0x4f, 0xdc, 0x22, 0x2a, 0x90, 0x88, 0x46, 0xee, 0xb8, 0x14, 0xde, 0x5e, 0x0b, 0xdb,
        0xe0, 0x32, 0x3a, 0x0a, 0x49, 0x06, 0x24, 0x5c, 0xc2, 0xd3, 0xac, 0x62, 0x91, 0x95, 0xe4, 0x79,
        0xe7, 0xc8, 0x37, 0x6d, 0x8d, 0xd5, 0x4e, 0xa9, 0x6c, 0x56, 0xf4, 0xea, 0x65, 0x7a, 0xae, 0x08,
        0xba, 0x78, 0x25, 0x2e, 0x1c, 0xa6, 0xb4, 0xc6, 0xe8, 0xdd, 0x74, 0x1f, 0x4b, 0xbd, 0x8b, 0x8a,
        0x70, 0x3e, 0xb5, 0x66, 0x48, 0x03, 0xf6, 0x0e, 0x61, 0x35, 0x57, 0xb9, 0x86, 0xc1, 0x1d, 0x9e,
        0xe1, 0xf8, 0x98, 0x11, 0x69, 0xd9, 0x8e, 0x94, 0x9b, 0x1e, 0x87, 0xe9, 0xce, 0x55, 0x28, 0xdf,
        0x8c, 0xa1, 0x89, 0x0d, 0xbf, 0xe6, 0x42, 0x68, 0x41, 0x99, 0x2d, 0x0f, 0xb0, 0x54, 0xbb, 0x16
    ]

    # AES Rcon (Round constants)
    RCON = [0x00, 0x01, 0x02, 0x04, 0x08, 0x10, 0x20, 0x40, 0x80, 0x1B, 0x36]

    def __init__(self):
        self.expanded_key = [0] * 44
        self.decrypted_data = 0
        self.inv_s_box = [self.S_BOX.index(i) for i in range(256)]

    def reset(self):
        self.expanded_key = [0] * 44
        self.decrypted_data = 0

    def sub_word(self, word):
        return (self.S_BOX[(word >> 24) & 0xFF] << 24) |\
               (self.S_BOX[(word >> 16) & 0xFF] << 16) |\
               (self.S_BOX[(word >> 8) & 0xFF] << 8) |\
               (self.S_BOX[word & 0xFF])

    def rot_word(self, word):
        return ((word << 8) & 0xFFFFFFFF) | (word >> 24)

    def update_key(self, key):
        assert 0 <= key < (1 << 128), "Key must be a 128-bit integer."

        for i in range(4):
            self.expanded_key[i] = (key >> (96 - i * 32)) & 0xFFFFFFFF

        for i in range(4, 44):
            temp = self.expanded_key[i - 1]
            if i % 4 == 0:
                temp = self.sub_word(self.rot_word(temp)) ^ (self.RCON[i // 4] << 24)
            self.expanded_key[i] = self.expanded_key[i - 4] ^ temp

    def get_key(self):
        return sum(self.expanded_key[i] << (32 * (43 - i)) for i in range(44))

    def decrypt(self, ciphertext):
        assert 0 <= ciphertext < (1 << 128), "Ciphertext must be a 128-bit integer."

        # Convert ciphertext to 4x4 state matrix (column-major order)
        state = [[(ciphertext >> (120 - 8 * (i + 4 * j))) & 0xFF for j in range(4)] for i in range(4)]

        # Initial AddRoundKey
        self.add_round_key(state, 10)

        # 9 main rounds (reverse order)
        for round in range(9, 0, -1):
            self.inv_shift_rows(state)
            self.inv_sub_bytes(state)
            self.add_round_key(state, round)
            self.inv_mix_columns(state)

        # Final round (no MixColumns)
        self.inv_shift_rows(state)
        self.inv_sub_bytes(state)
        self.add_round_key(state, 0)

        # Convert state matrix back to 128-bit integer
        self.decrypted_data = 0
        for j in range(4):
            for i in range(4):
                self.decrypted_data = (self.decrypted_data << 8) | state[i][j]

    def add_round_key(self, state, round):
        for j in range(4):
            word = self.expanded_key[round * 4 + j]
            for i in range(4):
                state[i][j] ^= (word >> (24 - 8 * i)) & 0xFF

    def inv_sub_bytes(self, state):
        for i in range(4):
            for j in range(4):
                state[i][j] = self.inv_s_box[state[i][j]]

    def inv_shift_rows(self, state):
        state[1][0], state[1][1], state[1][2], state[1][3] = state[1][3], state[1][0], state[1][1], state[1][2]
        state[2][0], state[2][1], state[2][2], state[2][3] = state[2][2], state[2][3], state[2][0], state[2][1]
        state[3][0], state[3][1], state[3][2], state[3][3] = state[3][1], state[3][2], state[3][3], state[3][0]

    def inv_mix_columns(self, state):
        for j in range(4):
            a = state[0][j], state[1][j], state[2][j], state[3][j]
            state[0][j] = self.gmul(a[0], 0x0E) ^ self.gmul(a[1], 0x0B) ^ self.gmul(a[2], 0x0D) ^ self.gmul(a[3], 0x09)
            state[1][j] = self.gmul(a[0], 0x09) ^ self.gmul(a[1], 0x0E) ^ self.gmul(a[2], 0x0B) ^ self.gmul(a[3], 0x0D)
            state[2][j] = self.gmul(a[0], 0x0D) ^ self.gmul(a[1], 0x09) ^ self.gmul(a[2], 0x0E) ^ self.gmul(a[3], 0x0B)
            state[3][j] = self.gmul(a[0], 0x0B) ^ self.gmul(a[1], 0x0D) ^ self.gmul(a[2], 0x09) ^ self.gmul(a[3], 0x0E)

    def gmul(self, a, b):
        """Galois Field multiplication of two bytes"""
        p = 0
        for _ in range(8):
            if b & 1:
                p ^= a
            hi_bit_set = a & 0x80
            a = (a << 1) & 0xFF
            if hi_bit_set:
                a ^= 0x1B
            b >>= 1
        return p

